const body = $input.first().json.body ?? $input.first().json;

const errorType = body.error_type ?? 'other';
const productCategory = body.product_category ?? 'desconocido';
const description = body.description ?? '';
const promptUsed = (body.prompt_used ?? '').slice(0, 800);

// Texto concatenado para generar el embedding
const text = `[${errorType}] Producto: ${productCategory}. Error: ${description}. Prompt original: ${promptUsed}`;

return [{
  json: {
    feedback_id: body.feedback_id,
    error_type: errorType,
    product_category: productCategory,
    description,
    prompt_used: promptUsed,
    embedding_text: text
  }
}];

// Llamar a la API de Gemini Embeddings directamente usando la credencial googlePalmApi
// El nodo Code puede acceder a credenciales via $credentials en versiones recientes,
// pero lo más confiable es usar el nodo HTTP Request con la credencial OAuth.
// Este nodo prepara el payload para el siguiente nodo HTTP.
const text = $input.first().json.embedding_text;
const feedbackId = $input.first().json.feedback_id;

return [{
  json: {
    feedback_id: feedbackId,
    embedding_text: text,
    // Pasar todos los campos para el nodo de guardado
    ...$input.first().json
  }
}];

const response = $input.first().json;

// La respuesta de Gemini embedContent: { embedding: { values: [...768 floats] } }
const embedding = response.embedding?.values ?? [];

if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error(`Gemini no devolvió embedding válido. Respuesta: ${JSON.stringify(response).slice(0, 400)}`);
}

if (embedding.length !== 768) {
  throw new Error(`Dimensión incorrecta: esperadas 768, recibidas ${embedding.length}`);
}

const feedbackId = $('Construir texto para embedding').first().json.feedback_id;

if (!feedbackId) {
  throw new Error('feedback_id no encontrado en el contexto');
}

return [{
  json: {
    feedback_id: feedbackId,
    embedding,
    dimensions: embedding.length
  }
}];
